SELECT FROM biz_merchant WHERE is_deleted = 0 AND status = #{status}
AND (shop_name LIKE CONCAT('%', #{keyword}, '%') OR category LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY rating DESC, sales DESC

mapper.update:
UPDATE biz_merchant
shop_name = #{shopName}, shop_logo = #{shopLogo}, shop_address = #{shopAddress}, description = #{description}, category = #{category}, business_hours = #{businessHours}, rating = #{rating}, sales = #{sales}, status = #{status}, update_time = NOW()
WHERE id = #{id}
